import csv
import json
from pathlib import Path
from typing import Any

from .models import DictEntry, RawRecord, StatPeriod, ThresholdRule, GradeLevel


class DataLoader:
    REQUIRED_FIELDS: list[str] = [
        "record_id",
        "river_name",
        "outfall_code",
        "monitor_time",
        "pollutant_code",
        "monitor_value",
    ]

    def __init__(self, encoding: str = "utf-8-sig"):
        self.encoding = encoding

    def load_raw_records(self, path: str | Path) -> list[RawRecord]:
        path = Path(path)
        if path.suffix.lower() == ".csv":
            return self._load_raw_csv(path)
        if path.suffix.lower() == ".json":
            return self._load_raw_json(path)
        raise ValueError(f"unsupported file type: {path.suffix}")

    def _load_raw_csv(self, path: Path) -> list[RawRecord]:
        records: list[RawRecord] = []
        with open(path, encoding=self.encoding, newline="") as f:
            reader = csv.DictReader(f)
            for row in reader:
                records.append(self._row_to_record(row))
        return records

    def _load_raw_json(self, path: Path) -> list[RawRecord]:
        with open(path, encoding=self.encoding) as f:
            data = json.load(f)
        if isinstance(data, list):
            return [self._row_to_record(item) for item in data]
        if isinstance(data, dict) and "records" in data:
            return [self._row_to_record(item) for item in data["records"]]
        raise ValueError("unexpected JSON structure for raw records")

    @staticmethod
    def _row_to_record(row: dict[str, Any]) -> RawRecord:
        monitor_value = row.get("monitor_value")
        if monitor_value is not None and monitor_value != "":
            try:
                monitor_value = float(monitor_value)
            except (ValueError, TypeError):
                monitor_value = None

        known_keys = {
            "record_id", "river_name", "outfall_code", "outfall_name",
            "monitor_time", "pollutant_code", "pollutant_name",
            "monitor_value", "unit", "region_code", "region_name",
            "source_system", "source_batch",
        }
        extra = {k: v for k, v in row.items() if k not in known_keys and v is not None and v != ""}

        return RawRecord(
            record_id=str(row.get("record_id", "")).strip(),
            river_name=str(row.get("river_name", "")).strip(),
            outfall_code=str(row.get("outfall_code", "")).strip(),
            outfall_name=str(row.get("outfall_name", "")).strip(),
            monitor_time=str(row.get("monitor_time", "")).strip(),
            pollutant_code=str(row.get("pollutant_code", "")).strip(),
            pollutant_name=str(row.get("pollutant_name", "")).strip(),
            monitor_value=monitor_value,
            unit=str(row.get("unit", "")).strip(),
            region_code=str(row.get("region_code", "")).strip(),
            region_name=str(row.get("region_name", "")).strip(),
            source_system=str(row.get("source_system", "")).strip(),
            source_batch=str(row.get("source_batch", "")).strip(),
            extra=extra,
        )

    def load_dict_entries(self, path: str | Path) -> list[DictEntry]:
        path = Path(path)
        with open(path, encoding=self.encoding) as f:
            if path.suffix.lower() == ".csv":
                reader = csv.DictReader(f)
                rows = list(reader)
            elif path.suffix.lower() == ".json":
                data = json.load(f)
                rows = data if isinstance(data, list) else data.get("entries", [])
            else:
                raise ValueError(f"unsupported file type: {path.suffix}")
        return [
            DictEntry(
                category=str(r.get("category", "")).strip(),
                code=str(r.get("code", "")).strip(),
                name=str(r.get("name", "")).strip(),
                alias=str(r.get("alias", "")).strip(),
                parent_code=str(r.get("parent_code", "")).strip(),
            )
            for r in rows
        ]

    def load_threshold_rules(self, path: str | Path) -> list[ThresholdRule]:
        path = Path(path)
        with open(path, encoding=self.encoding) as f:
            if path.suffix.lower() == ".json":
                data = json.load(f)
                rows = data if isinstance(data, list) else data.get("rules", [])
            elif path.suffix.lower() == ".csv":
                reader = csv.DictReader(f)
                rows = list(reader)
            else:
                raise ValueError(f"unsupported file type: {path.suffix}")

        rules: list[ThresholdRule] = []
        for r in rows:
            grade_str = str(r.get("grade_level", "normal")).strip().lower()
            try:
                grade = GradeLevel(grade_str)
            except ValueError:
                grade = GradeLevel.NORMAL

            min_val = r.get("min_value")
            max_val = r.get("max_value")
            if min_val is not None and min_val != "":
                min_val = float(min_val)
            else:
                min_val = None
            if max_val is not None and max_val != "":
                max_val = float(max_val)
            else:
                max_val = None

            rules.append(ThresholdRule(
                rule_id=str(r.get("rule_id", "")).strip(),
                pollutant_code=str(r.get("pollutant_code", "")).strip(),
                grade_level=grade,
                min_value=min_val,
                max_value=max_val,
                description=str(r.get("description", "")).strip(),
                priority=int(r.get("priority", 0) or 0),
                enabled=str(r.get("enabled", "true")).strip().lower() in ("true", "1", "yes"),
                source_system=str(r.get("source_system", "")).strip(),
            ))
        return [r for r in rules if r.enabled]

    def load_stat_periods(self, path: str | Path) -> list[StatPeriod]:
        path = Path(path)
        with open(path, encoding=self.encoding) as f:
            if path.suffix.lower() == ".json":
                data = json.load(f)
                rows = data if isinstance(data, list) else data.get("periods", [])
            elif path.suffix.lower() == ".csv":
                reader = csv.DictReader(f)
                rows = list(reader)
            else:
                raise ValueError(f"unsupported file type: {path.suffix}")

        periods: list[StatPeriod] = []
        for r in rows:
            group_by = r.get("group_by_fields", "")
            if isinstance(group_by, str):
                group_by = [f.strip() for f in group_by.split(",") if f.strip()]
            elif isinstance(group_by, list):
                group_by = [str(f).strip() for f in group_by]
            else:
                group_by = []

            periods.append(StatPeriod(
                period_id=str(r.get("period_id", "")).strip(),
                period_type=str(r.get("period_type", "")).strip(),
                start_time=str(r.get("start_time", "")).strip(),
                end_time=str(r.get("end_time", "")).strip(),
                group_by_fields=group_by,
            ))
        return periods
