from typing import Any

from .models import (
    DictEntry,
    IssueType,
    RawRecord,
    ThresholdRule,
    ValidationResult,
)


class Validator:
    REQUIRED_FIELDS: list[str] = [
        "record_id",
        "river_name",
        "outfall_code",
        "monitor_time",
        "pollutant_code",
        "monitor_value",
    ]

    def __init__(
        self,
        dict_entries: list[DictEntry] | None = None,
        rules: list[ThresholdRule] | None = None,
    ):
        self.dict_entries = dict_entries or []
        self.rules = rules or []
        self._dict_lookup: dict[str, DictEntry] = {}
        for entry in self.dict_entries:
            self._dict_lookup[entry.code] = entry
            if entry.alias:
                self._dict_lookup[entry.alias] = entry
        self._rule_conflicts = self._detect_rule_conflicts()

    def _detect_rule_conflicts(self) -> list[dict[str, Any]]:
        conflicts: list[dict[str, Any]] = []
        seen: set[frozenset[str]] = set()
        for i, r1 in enumerate(self.rules):
            for r2 in self.rules[i + 1:]:
                if r1.conflicts_with(r2):
                    pair = frozenset({r1.rule_id, r2.rule_id})
                    if pair not in seen:
                        seen.add(pair)
                        conflicts.append({
                            "rule_id_1": r1.rule_id,
                            "rule_id_2": r2.rule_id,
                            "pollutant_code": r1.pollutant_code,
                            "grade_level": r1.grade_level.value,
                            "description": f"threshold ranges overlap for pollutant {r1.pollutant_code} grade {r1.grade_level.value}",
                        })
        return conflicts

    def get_rule_conflicts(self) -> list[dict[str, Any]]:
        return list(self._rule_conflicts)

    def validate_record(self, record: RawRecord) -> ValidationResult:
        result = ValidationResult(record_id=record.record_id)

        self._check_required_fields(record, result)
        self._check_value_range(record, result)
        self._check_dict_consistency(record, result)

        return result

    def validate_batch(self, records: list[RawRecord]) -> list[ValidationResult]:
        return [self.validate_record(r) for r in records]

    def _check_required_fields(self, record: RawRecord, result: ValidationResult):
        field_map: dict[str, Any] = {
            "record_id": record.record_id,
            "river_name": record.river_name,
            "outfall_code": record.outfall_code,
            "monitor_time": record.monitor_time,
            "pollutant_code": record.pollutant_code,
            "monitor_value": record.monitor_value,
        }
        for field_name, value in field_map.items():
            if value is None or value == "":
                result.add_issue(
                    IssueType.MISSING_FIELD,
                    field_name,
                    f"required field '{field_name}' is missing or empty",
                )

    def _check_value_range(self, record: RawRecord, result: ValidationResult):
        if record.monitor_value is None:
            return
        if record.monitor_value < 0:
            result.add_issue(
                IssueType.INVALID_VALUE,
                "monitor_value",
                f"monitor_value cannot be negative: {record.monitor_value}",
                {"value": record.monitor_value},
            )

    def _check_dict_consistency(self, record: RawRecord, result: ValidationResult):
        if record.pollutant_code and record.pollutant_code not in self._dict_lookup:
            if record.pollutant_name:
                pass
            else:
                result.add_issue(
                    IssueType.INVALID_VALUE,
                    "pollutant_code",
                    f"pollutant_code '{record.pollutant_code}' not found in dictionary and pollutant_name is also missing",
                    {"pollutant_code": record.pollutant_code},
                )

        if record.region_code and record.region_code not in self._dict_lookup:
            pass

        if record.pollutant_code in self._dict_lookup:
            dict_entry = self._dict_lookup[record.pollutant_code]
            if record.pollutant_name and dict_entry.name and record.pollutant_name != dict_entry.name:
                if record.pollutant_name != dict_entry.alias:
                    result.add_issue(
                        IssueType.RULE_CONFLICT,
                        "pollutant_name",
                        f"pollutant_name '{record.pollutant_name}' conflicts with dictionary name '{dict_entry.name}' for code '{record.pollutant_code}'",
                        {
                            "pollutant_code": record.pollutant_code,
                            "record_name": record.pollutant_name,
                            "dict_name": dict_entry.name,
                        },
                    )

    def validate_rules(self) -> list[dict[str, Any]]:
        return self._rule_conflicts
