from .models import DeduplicationResult, RawRecord


class Deduplicator:
    DEFAULT_DEDUP_KEYS: list[str] = [
        "outfall_code",
        "monitor_time",
        "pollutant_code",
    ]

    def __init__(self, dedup_keys: list[str] | None = None, keep: str = "last"):
        self.dedup_keys = dedup_keys or self.DEFAULT_DEDUP_KEYS
        self.keep = keep

    def deduplicate(self, records: list[RawRecord]) -> DeduplicationResult:
        seen: dict[str, list[RawRecord]] = {}
        for record in records:
            key = self._make_key(record)
            if key not in seen:
                seen[key] = []
            seen[key].append(record)

        kept: list[RawRecord] = []
        duplicates: list[RawRecord] = []

        for key, group in seen.items():
            if len(group) == 1:
                kept.append(group[0])
            else:
                sorted_group = sorted(group, key=lambda r: r.record_id)
                if self.keep == "last":
                    kept.append(sorted_group[-1])
                    duplicates.extend(sorted_group[:-1])
                else:
                    kept.append(sorted_group[0])
                    duplicates.extend(sorted_group[1:])

        return DeduplicationResult(
            kept=kept,
            duplicates=duplicates,
            dedup_keys=list(self.dedup_keys),
        )

    def _make_key(self, record: RawRecord) -> str:
        parts: list[str] = []
        for k in self.dedup_keys:
            val = getattr(record, k, None)
            parts.append(str(val) if val is not None else "")
        return "|||".join(parts)
