from .models import GradeLevel, GradingResult, RawRecord, ThresholdRule


class Grader:
    def __init__(self, rules: list[ThresholdRule]):
        self.rules = sorted(rules, key=lambda r: r.priority, reverse=True)
        self._rules_by_pollutant: dict[str, list[ThresholdRule]] = {}
        for rule in self.rules:
            if rule.pollutant_code not in self._rules_by_pollutant:
                self._rules_by_pollutant[rule.pollutant_code] = []
            self._rules_by_pollutant[rule.pollutant_code].append(rule)

    def grade_record(self, record: RawRecord) -> GradingResult:
        result = GradingResult(record=record)
        applicable = self._rules_by_pollutant.get(record.pollutant_code, [])

        if not applicable or record.monitor_value is None:
            result.grade_level = GradeLevel.NORMAL
            result.explanation = "no applicable rules or missing value, defaulting to normal"
            return result

        matched: list[ThresholdRule] = []
        for rule in applicable:
            if self._value_matches(record.monitor_value, rule):
                matched.append(rule)

        if not matched:
            result.grade_level = GradeLevel.NORMAL
            result.explanation = f"value {record.monitor_value} did not match any threshold rules"
            return result

        matched.sort(key=lambda r: r.priority, reverse=True)
        best = matched[0]
        result.grade_level = best.grade_level
        result.matched_rules = [r.rule_id for r in matched]
        result.explanation = (
            f"value {record.monitor_value} matched rule '{best.rule_id}' "
            f"(grade={best.grade_level.value}, range=[{best.min_value}, {best.max_value}])"
        )

        return result

    def grade_batch(self, records: list[RawRecord]) -> list[GradingResult]:
        return [self.grade_record(r) for r in records]

    @staticmethod
    def _value_matches(value: float, rule: ThresholdRule) -> bool:
        if rule.min_value is not None and value < rule.min_value:
            return False
        if rule.max_value is not None and value > rule.max_value:
            return False
        return True
