from collections import defaultdict
from typing import Any

from .models import (
    BadDataEntry,
    GradeLevel,
    GradingResult,
    GroupReport,
    RawRecord,
    ReviewEntry,
    StatPeriod,
    ValidationResult,
)


class Aggregator:
    def __init__(
        self,
        stat_periods: list[StatPeriod],
        process_batch: str = "",
        source_system: str = "",
    ):
        self.stat_periods = stat_periods
        self.process_batch = process_batch
        self.source_system = source_system

    def build_group_reports(
        self,
        valid_records: list[RawRecord],
        grading_results: list[GradingResult],
    ) -> list[GroupReport]:
        record_grades: dict[str, GradingResult] = {}
        for gr in grading_results:
            record_grades[gr.record.record_id] = gr

        all_reports: list[GroupReport] = []

        for period in self.stat_periods:
            period_records = [
                gr
                for gr in grading_results
                if period.contains(gr.record.monitor_time)
            ]
            if not period_records:
                continue

            group_by = period.group_by_fields or ["river_name", "pollutant_code"]
            groups: dict[str, list[GradingResult]] = defaultdict(list)
            for gr in period_records:
                key = self._make_group_key(gr.record, group_by)
                groups[key].append(gr)

            for key_str, group_items in groups.items():
                values = [
                    gr.record.monitor_value
                    for gr in group_items
                    if gr.record.monitor_value is not None
                ]
                if not values:
                    continue

                grade_dist: dict[str, int] = defaultdict(int)
                for gr in group_items:
                    grade_dist[gr.grade_level.value] += 1

                group_key = self._parse_group_key(key_str, group_by)

                src_sys = self.source_system
                if group_items:
                    rec_sys = group_items[0].record.source_system
                    if rec_sys:
                        src_sys = rec_sys

                report = GroupReport(
                    group_key=group_key,
                    record_count=len(group_items),
                    value_sum=round(sum(values), 6),
                    value_avg=round(sum(values) / len(values), 6),
                    value_max=max(values),
                    value_min=min(values),
                    grade_distribution=dict(grade_dist),
                    process_batch=self.process_batch,
                    source_system=src_sys,
                )
                all_reports.append(report)

        return all_reports

    def build_bad_data_entries(
        self,
        invalid_results: list[tuple[RawRecord, ValidationResult]],
    ) -> list[BadDataEntry]:
        entries: list[BadDataEntry] = []
        for record, vr in invalid_results:
            src_sys = self.source_system
            if record.source_system:
                src_sys = record.source_system

            entries.append(BadDataEntry(
                record_id=record.record_id,
                source_record=record.to_dict(),
                issues=vr.issues,
                process_batch=self.process_batch,
                source_system=src_sys,
            ))
        return entries

    def build_review_entries(
        self,
        grading_results: list[GradingResult],
    ) -> list[ReviewEntry]:
        entries: list[ReviewEntry] = []
        for gr in grading_results:
            if gr.grade_level in (GradeLevel.WARNING, GradeLevel.CRITICAL):
                reason = gr.explanation
                if gr.grade_level == GradeLevel.CRITICAL:
                    reason = f"[CRITICAL] {reason}"
                elif gr.grade_level == GradeLevel.WARNING:
                    reason = f"[WARNING] {reason}"

                entries.append(ReviewEntry(
                    record_id=gr.record.record_id,
                    river_name=gr.record.river_name,
                    outfall_code=gr.record.outfall_code,
                    outfall_name=gr.record.outfall_name,
                    pollut_code=gr.record.pollutant_code,
                    pollutant_name=gr.record.pollutant_name,
                    monitor_time=gr.record.monitor_time,
                    monitor_value=gr.record.monitor_value,
                    unit=gr.record.unit,
                    grade_level=gr.grade_level.value,
                    review_reason=reason,
                    process_batch=self.process_batch,
                    source_system=gr.record.source_system or self.source_system,
                    source_batch=gr.record.source_batch,
                ))
        return entries

    @staticmethod
    def _make_group_key(record: RawRecord, group_by: list[str]) -> str:
        parts: list[str] = []
        for field in group_by:
            val = getattr(record, field, "")
            parts.append(f"{field}={val}")
        return "|".join(parts)

    @staticmethod
    def _parse_group_key(key_str: str, group_by: list[str]) -> dict[str, Any]:
        result: dict[str, Any] = {}
        for part in key_str.split("|"):
            if "=" in part:
                k, v = part.split("=", 1)
                result[k] = v
        return result
